// 解析sitemap，提取所有URL
const sitemapXml = $input.first().json.response || '';
const config = JSON.parse($json.submitConfig);

// 提取sitemap中的所有URL
const urlRegex = /<loc>([^<]+)<\/loc>/g;
const urls = [];
let match;
while ((match = urlRegex.exec(sitemapXml)) !== null) {
  urls.push(match[1]);
}

// 按优先级分类
const priorities = {
  high: [],    // 首页、目的地页
  medium: [],  // 研学、自驾页
  low: []      // 其他页
};

for (const url of urls) {
  if (url.includes('/destinations/') || url === config.siteUrl + '/') {
    priorities.high.push(url);
  } else if (url.includes('/study-tours/') || url.includes('/self-drive/') || url.includes('/themes/')) {
    priorities.medium.push(url);
  } else {
    priorities.low.push(url);
  }
}

return [{
  json: {
    totalUrls: urls.length,
    highPriority: priorities.high,
    mediumPriority: priorities.medium,
    lowPriority: priorities.low,
    siteUrl: config.siteUrl,
    fetchedAt: new Date().toISOString()
  }
}];

// 解析百度提交结果
const baiduResponse = $input.first().json;

let result = {
  platform: '百度搜索资源平台',
  success: false,
  message: '',
  remainingQuota: null,
  submittedAt: new Date().toISOString()
};

// 解析百度API响应
if (baiduResponse && baiduResponse.success !== undefined) {
  result.success = baiduResponse.success;
  result.message = baiduResponse.message || baiduResponse.remain || '提交完成';
  result.remainingQuota = baiduResponse.remain;
} else if (typeof baiduResponse === 'string') {
  // 百度可能返回HTML，需要提取关键信息
  if (baiduResponse.includes('成功') || baiduResponse.includes('success')) {
    result.success = true;
    result.message = '提交成功';
  } else {
    result.message = '提交完成（请手动确认）';
  }
} else {
  result.message = '提交完成';
  result.success = true;
}

return [result];

// 记录提交结果
const sitemapInfo = $('解析Sitemap').first().json;
const baiduResult = $('解析百度结果').first().json;
const googleResult = $input.first().json;

const report = {
  reportTime: new Date().toLocaleString('zh-CN'),
  siteUrl: sitemapInfo.siteUrl,
  sitemapUrl: sitemapInfo.sitemapUrl,
  totalUrls: sitemapInfo.totalUrls,
  submissions: [
    {
      platform: '百度搜索资源平台',
      status: baiduResult.success ? '✅ 成功' : '⚠️ 待确认',
      message: baiduResult.message,
      remainingQuota: baiduResult.remainingQuota
    },
    {
      platform: 'Google Search Console',
      status: googleResult && (googleResult.success || googleResult.status === 200) ? '✅ 成功' : '⚠️ 待确认',
      message: 'Sitemap自动提交'
    }
  ],
  nextActions: [
    '登录百度搜索资源平台确认抓取状态',
    '检查Google Search Console中的覆盖率',
    '监控新页面的收录速度'
  ]
};

return [report];
